mapper.select:
SELECT COUNT(*) AS cnt
FROM TBL_INOUT_WAREHOUSE W
LEFT JOIN TBL_COM_PLANT P ON W.PLANTCD = P.PLANTCD
LEFT JOIN TBL_COM_COMPANY C ON W.COMPANYCD = C.COMPANYCD

    W.USEYN = 1
    AND W.INDAY >= #{start_date}
    AND W.INDAY <= #{end_date}
    AND W.PLANTCD = #{plant_cd}
    AND W.COMPANYCD = #{company_cd}
    AND W.ORDERNUM = #{order_num}
    AND (C.COMPANYNM LIKE #{search})

SELECT W.WAREHOUSENUM, W.PLANTCD, P.PLANTNM, W.COMPANYCD, C.COMPANYNM,
       W.ORDERNUM, W.INDAY, W.INGUBUN, W.WHSTATE,
       (SELECT ISNULL(SUM(D.INLOTQTY * ISNULL(D.UNIT_PRICE,0)),0) FROM TBL_INOUT_WAREHOUSE_DETAIL D WHERE D.WAREHOUSENUM = W.WAREHOUSENUM AND D.USEYN=1) AS TOTALAMT
FROM TBL_INOUT_WAREHOUSE W
LEFT JOIN TBL_COM_PLANT P ON W.PLANTCD = P.PLANTCD
LEFT JOIN TBL_COM_COMPANY C ON W.COMPANYCD = C.COMPANYCD

    W.USEYN = 1
    AND W.INDAY >= #{start_date}
    AND W.INDAY <= #{end_date}
    AND W.PLANTCD = #{plant_cd}
    AND W.COMPANYCD = #{company_cd}
    AND W.ORDERNUM = #{order_num}
    AND (C.COMPANYNM LIKE #{search})

ORDER BY W.WAREHOUSENUM DESC
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

mapper.update:
UPDATE TBL_INOUT_PURCHASE_ORDER
SET ORDERSTATE = #{ORDERSTATE}, EDITDTM = GETDATE()
WHERE ORDERNUM = #{ORDERNUM}

UPDATE TBL_INOUT_PURCHASE_ORDER_DETAIL
SET INQTY = ISNULL(INQTY, 0) + #{INLOTQTY}
WHERE ORDERNUM = #{ORDERNUM} AND PARTNO = #{PARTNO}

UPDATE TBL_INOUT_PURCHASE_ORDER_DETAIL
SET INQTY = CASE WHEN ISNULL(INQTY, 0) - #{INLOTQTY} < 0 THEN 0 ELSE ISNULL(INQTY, 0) - #{INLOTQTY} END
WHERE ORDERNUM = #{ORDERNUM} AND PARTNO = #{PARTNO}
